import React from "react";
import MealCard from "../Components/MealCard";

const MealPlan = () => {
  const patientData = JSON.parse(localStorage.getItem("patientData")) || {};

  const meals = [
    {
      mealType: "Breakfast",
      mealName: "Oatmeal with Fruits",
      calories: 350,
      protein: 10,
      carbs: 55,
      bgColor: "#ffe0b2",
      image: "https://images.unsplash.com/photo-1572449043411-0a7f726bd7de?auto=format&fit=crop&w=800&q=80",
    },
    {
      mealType: "Lunch",
      mealName: "Grilled Chicken Salad",
      calories: 400,
      protein: 35,
      carbs: 45,
      bgColor: "#c8e6c9",
      image: "https://images.unsplash.com/photo-1604908177520-4b0e6e4fba3b?auto=format&fit=crop&w=800&q=80",
    },
    {
      mealType: "Dinner",
      mealName: "Steamed Fish with Veggies",
      calories: 350,
      protein: 30,
      carbs: 35,
      bgColor: "#bbdefb",
      image: "https://images.unsplash.com/photo-1604908177040-7c0a3fdfad4a?auto=format&fit=crop&w=800&q=80",
    },
  ];

  return (
    <div className="container my-5">
      <h2 className="text-center mb-4">Meal Plan for {patientData.patientName || "Patient"}</h2>
      <div className="row g-4">
        {meals.map((meal, idx) => (
          <div className="col-md-4" key={idx}>
            <MealCard {...meal} />
          </div>
        ))}
      </div>
    </div>
  );
};

export default MealPlan;
